%%%%%%%%%% Function fCosyInpV01.m %%%%%%%%%%% Function Cosy Input maker, ver.1% Kei Nakamura% Created on Saturday, July 21th 2007.% Modified on %% function strOut = fCosyInpV01(esc,nmb);% make strimg cell for cosy output% strOut: string cell output% name: name in cosy variance% dat: datafunction strOut = fCosyInpV01(name,dat);  %function headernmb = numel(dat);for ii=1:nmb    strOut{ii} = [name '(' num2str(ii) ') := ' num2str(dat(ii)) ' ;'];end
